```class Solution:
    def minSwaps(self, s: str) -> int:
        n = len(s)
        open_brackets = n // 2
        close_brackets = n // 2
        swaps = 0
        for i in range(n):
            if s[i] == '[':
                if open_brackets > 0:
                    open_brackets -= 1
                else:
                    swaps += 1
            else:
                if close_brackets > 0:
                    close_brackets -= 1
                else:
                    swaps += 1
        return swaps
```

